#!/usr/bin/env python3
"""
Dependency Management Script for Python Projects
==============================================

This script provides tools for managing Python dependency lock files
to ensure consistent versions across development and production environments.

Usage:
    python dependency_manager.py generate
    python dependency_manager.py update
    python dependency_manager.py verify
"""

import os
import sys
import subprocess
import hashlib
import json
from pathlib import Path
from typing import List, Dict, Optional

class DependencyManager:
    def __init__(self, project_dir: str = "."):
        self.project_dir = Path(project_dir)
        self.requirements_file = self.project_dir / "requirements.txt"
        self.poetry_lock_file = self.project_dir / "poetry.lock"
        self.pipfile_lock = self.project_dir / "Pipfile.lock"
        
    def generate_requirements_txt(self) -> bool:
        """Generate requirements.txt with hashes using pip-compile"""
        try:
            if not self.requirements_file.exists():
                # Create initial requirements.in
                with open(self.project_dir / "requirements.in", "w") as f:
                    f.write("# Base requirements\n")
                
            # Generate requirements.txt with hashes
            subprocess.run([
                "pip-compile", 
                "--generate-hashes",
                "--output-file", str(self.requirements_file),
                str(self.project_dir / "requirements.in")
            ], check=True, capture_output=True)
            
            print("✅ Generated requirements.txt with hashes")
            return True
        except subprocess.CalledProcessError as e:
            print(f"❌ Error generating requirements.txt: {e}")
            return False
            
    def update_dependencies(self) -> bool:
        """Update dependencies in requirements.txt"""
        try:
            subprocess.run([
                "pip-compile", 
                "--upgrade",
                "--generate-hashes",
                "--output-file", str(self.requirements_file),
                str(self.project_dir / "requirements.in")
            ], check=True, capture_output=True)
            
            print("✅ Updated dependencies in requirements.txt")
            return True
        except subprocess.CalledProcessError as e:
            print(f"❌ Error updating dependencies: {e}")
            return False
            
    def generate_poetry_lock(self) -> bool:
        """Generate Poetry lock file"""
        try:
            subprocess.run(["poetry", "lock", "--no-update"], check=True, capture_output=True)
            print("✅ Generated poetry.lock file")
            return True
        except subprocess.CalledProcessError as e:
            print(f"❌ Error generating poetry.lock: {e}")
            return False
            
    def verify_dependencies(self) -> bool:
        """Verify that dependencies match lock files"""
        try:
            if self.poetry_lock_file.exists():
                # Verify poetry.lock integrity
                result = subprocess.run(
                    ["poetry", "lock", "--check"], 
                    capture_output=True, 
                    text=True
                )
                if result.returncode == 0:
                    print("✅ Poetry lock file is valid")
                else:
                    print(f"❌ Poetry lock file verification failed: {result.stderr}")
                    return False
                    
            elif self.requirements_file.exists():
                # Verify requirements.txt integrity
                with open(self.requirements_file, "r") as f:
                    lines = f.readlines()
                
                # Check for hashes
                hash_count = sum(1 for line in lines if line.strip().startswith("--hash"))
                if hash_count > 0:
                    print("✅ requirements.txt contains hashes")
                else:
                    print("⚠️  requirements.txt does not contain hashes")
                    
            return True
        except Exception as e:
            print(f"❌ Error verifying dependencies: {e}")
            return False
            
    def install_dependencies(self) -> bool:
        """Install dependencies from lock files"""
        try:
            if self.poetry_lock_file.exists():
                subprocess.run(["poetry", "install"], check=True, capture_output=True)
                print("✅ Installed dependencies from poetry.lock")
            elif self.requirements_file.exists():
                subprocess.run([
                    "pip", "install", "--no-cache-dir", "-r", str(self.requirements_file)
                ], check=True, capture_output=True)
                print("✅ Installed dependencies from requirements.txt")
            else:
                print("❌ No lock file found")
                return False
                
            return True
        except subprocess.CalledProcessError as e:
            print(f"❌ Error installing dependencies: {e}")
            return False
            
    def create_dependency_strategy(self) -> Dict[str, str]:
        """Create dependency management strategy document"""
        strategy = {
            "lock_file_type": self._detect_lock_file(),
            "install_command": self._get_install_command(),
            "update_command": self._get_update_command(),
            "verification": self._get_verification_command()
        }
        
        with open(self.project_dir / "DEPENDENCY_STRATEGY.md", "w") as f:
            f.write("# Dependency Management Strategy\n\n")
            f.write(f"**Lock File Type:** {strategy['lock_file_type']}\n\n")
            f.write(f"**Install Command:** `{strategy['install_command']}`\n\n")
            f.write(f"**Update Command:** `{strategy['update_command']}`\n\n")
            f.write(f"**Verification Command:** `{strategy['verification']}`\n\n")
            
        return strategy
        
    def _detect_lock_file(self) -> str:
        """Detect which lock file is being used"""
        if self.poetry_lock_file.exists():
            return "Poetry lock file"
        elif self.requirements_file.exists():
            return "requirements.txt with hashes"
        else:
            return "No lock file detected"
            
    def _get_install_command(self) -> str:
        """Get install command based on lock file"""
        if self.poetry_lock_file.exists():
            return "poetry install"
        else:
            return "pip install -r requirements.txt"
            
    def _get_update_command(self) -> str:
        """Get update command based on lock file"""
        if self.poetry_lock_file.exists():
            return "poetry lock --no-update && poetry install"
        else:
            return "pip-compile --upgrade --generate-hashes requirements.in"
            
    def _get_verification_command(self) -> str:
        """Get verification command"""
        if self.poetry_lock_file.exists():
            return "poetry lock --check"
        else:
            return "pip-compile --check requirements.in"

def main():
    """Main entry point"""
    manager = DependencyManager()
    
    if len(sys.argv) < 2:
        print("Usage: python dependency_manager.py [generate|update|verify|install|strategy]")
        sys.exit(1)
        
    command = sys.argv[1]
    
    if command == "generate":
        success = manager.generate_requirements_txt()
        if success:
            manager.create_dependency_strategy()
    elif command == "update":
        success = manager.update_dependencies()
        if success:
            manager.create_dependency_strategy()
    elif command == "verify":
        manager.verify_dependencies()
    elif command == "install":
        manager.install_dependencies()
    elif command == "strategy":
        manager.create_dependency_strategy()
    else:
        print("Invalid command. Use: generate, update, verify, install, or strategy")
        sys.exit(1)

if __name__ == "__main__":
    main()